SELECT model_name, warranty_period
FROM filter_models
WHERE warranty_period > 12;

SELECT filter_model_id, filtration_area, effective_filtration_area, filtration_media
FROM filtration_areas
WHERE filtration_area_id = 0;

SELECT COUNT(filter_model_id)
FROM filter_models
WHERE filter_class = 'M5' AND warranty_period >= 12;

SELECT model_name, description
FROM filter_models
WHERE filter_model_id = 0;

SELECT filter_model_id, effective_filtration_area
FROM filtration_areas
WHERE filtration_area > 3;

SELECT model_name, filter_class
FROM filter_models
ORDER BY model_name;

SELECT model_name, filter_class, description, warranty_period, AVG(weight) AS average_weight
FROM filter_models
GROUP BY model_name, filter_class, warranty_period, description;

SELECT width, height, depth, volume, surface_area
FROM filter_dimensions
WHERE filter_model_id = 1;
